import { createSlice, createAsyncThunk } from "@reduxjs/toolkit";
import axios from "../../axios";

// Tüm programları getirme (GET)
export const fetchAllSchedules = createAsyncThunk("rasps/fetchAllSchedules", async () => {
  const { data } = await axios.get("/schedules");
  return data;
});

// Yeni program oluşturma (POST)
export const createSchedule = createAsyncThunk("rasps/createSchedule", async (data) => {
  const { data: createdData } = await axios.post("/create-schedule", data);
  return createdData;
});

// Program silme (DELETE)
export const deleteSchedule = createAsyncThunk("rasps/deleteSchedule", async (id) => {
  await axios.delete(`/delete-schedule/${id}`);
  return id; // Silinen öğenin ID'sini döndürüyoruz
});

// Belirli bir programı getirme (GET)
export const fetchOneSchedule = createAsyncThunk("rasps/fetchOneSchedule", async (id) => {
  const { data } = await axios.get(`/schedule/${id}`);
  return data;
});

// Program güncelleme (PATCH)
export const updateSchedule = createAsyncThunk("rasps/updateSchedule", async ({ id, data }) => {
  const { data: updatedData } = await axios.patch(`/update-schedule/${id}`, data);
  return updatedData;
});

const initialState = {
  rasps: {
    items: [],
    status: "loading",
  },
};

const raspsSlice = createSlice({
  name: "rasps",
  initialState,
  reducers: {},
  extraReducers: {
    [fetchAllSchedules.pending]: (state) => {
      state.rasps.status = "loadingfetch";
    },
    [fetchAllSchedules.fulfilled]: (state, action) => {
      state.rasps.items = action.payload;
      state.rasps.status = "loadedfetch";
    },
    [fetchAllSchedules.rejected]: (state) => {
      state.rasps.items = [];
      state.rasps.status = "error";
    },
    [createSchedule.fulfilled]: (state, action) => {
      state.rasps.items.push(action.payload);
    },
    [deleteSchedule.fulfilled]: (state, action) => {
      state.rasps.items = state.rasps.items.filter((obj) => obj.id !== action.payload);
    },
    [fetchOneSchedule.pending]: (state) => {
      state.rasps.status = "loadingfetch";
    },
    [fetchOneSchedule.fulfilled]: (state, action) => {
      state.rasps.items = [action.payload];
      state.rasps.status = "loadedfetch";
    },
    [updateSchedule.fulfilled]: (state, action) => {
      state.rasps.items = state.rasps.items.map((obj) =>
        obj.id === action.payload.id ? action.payload : obj
      );
    },
  },
});

export const raspsReducer = raspsSlice.reducer;
